static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvStandard3dAsymmetricInputAsymmetricKernelCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);

    if (x_shape->GetDimNum() != 5 || w_shape->GetDimNum() != 5) {
        return ge::GRAPH_FAILED;
    }

    const uint32_t N   = static_cast<uint32_t>(x_shape->GetDim(0));
    const uint32_t Cin = static_cast<uint32_t>(x_shape->GetDim(1));
    const uint32_t inD = static_cast<uint32_t>(x_shape->GetDim(2));
    const uint32_t inH = static_cast<uint32_t>(x_shape->GetDim(3));
    const uint32_t inW = static_cast<uint32_t>(x_shape->GetDim(4));

    const uint32_t Cout = static_cast<uint32_t>(w_shape->GetDim(0));
    const uint32_t wCin = static_cast<uint32_t>(w_shape->GetDim(1));
    const uint32_t kD   = static_cast<uint32_t>(w_shape->GetDim(2));
    const uint32_t kH   = static_cast<uint32_t>(w_shape->GetDim(3));
    const uint32_t kW   = static_cast<uint32_t>(w_shape->GetDim(4));

    if (wCin != Cin) {
        return ge::GRAPH_FAILED;
    }
    if (inD < kD || inH < kH || inW < kW) {
        return ge::GRAPH_FAILED;
    }

    const uint32_t outD = inD - kD + 1;
    const uint32_t outH = inH - kH + 1;
    const uint32_t outW = inW - kW + 1;

    const uint64_t totalOut = static_cast<uint64_t>(N) * Cout * outD * outH * outW;

    // Choose conservative tile size; computation-heavy kernel, small tiles to distribute.
    uint32_t tileOut = 2048;
    if (totalOut < tileOut) {
        tileOut = static_cast<uint32_t>(totalOut);
        if (tileOut == 0) tileOut = 1;
    }

    const uint64_t numTiles = CeilDivU64(totalOut, tileOut);
    uint32_t blockDim = static_cast<uint32_t>(numTiles);
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;
    context->SetBlockDim(blockDim);

    tiling.set_n(N);
    tiling.set_cIn(Cin);
    tiling.set_cOut(Cout);
    tiling.set_inD(inD);
    tiling.set_inH(inH);
    tiling.set_inW(inW);
    tiling.set_kD(kD);
    tiling.set_kH(kH);
    tiling.set_kW(kW);
    tiling.set_outD(outD);
    tiling.set_outH(outH);
    tiling.set_outW(outW);
    tiling.set_totalOut(totalOut);
    tiling.set_tileOut(tileOut);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspace = context->GetWorkspaceSizes(1);
    workspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

